import React, { useState, useEffect } from 'react';
import axios from 'axios';

const ComplaintAnalysis = () => {
  const [complaints, setComplaints] = useState([]);
  const [stats, setStats] = useState({
    total: 0,
    pending: 0,
    resolved: 0,
    inProgress: 0,
  });
  const [selectedComplaint, setSelectedComplaint] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchComplaints();
  }, []);

  const fetchComplaints = async () => {
    try {
      const token = localStorage.getItem('govToken');
      const response = await axios.get('http://localhost:5000/api/gov/complaints', {
        headers: { Authorization: `Bearer ${token}` },
      });
      setComplaints(response.data);
      calculateStats(response.data);
    } catch (err) {
      console.error('Error fetching complaints:', err);
    } finally {
      setLoading(false);
    }
  };

  const calculateStats = (complaintsList) => {
    const stats = {
      total: complaintsList.length,
      pending: complaintsList.filter(c => c.status === 'pending').length,
      resolved: complaintsList.filter(c => c.status === 'resolved').length,
      inProgress: complaintsList.filter(c => c.status === 'in_progress').length,
    };
    setStats(stats);
  };

  const handleStatusUpdate = async (complaintId, newStatus) => {
    try {
      const token = localStorage.getItem('govToken');
      await axios.patch(
        `http://localhost:5000/api/gov/complaints/${complaintId}`,
        { status: newStatus },
        { headers: { Authorization: `Bearer ${token}` } }
      );
      fetchComplaints();
      setSelectedComplaint(null);
    } catch (err) {
      alert('Error updating complaint status');
    }
  };

  return (
    <div className="complaint-analysis">
      <div className="section-header">
        <h2>📋 Complaint Management & Analysis</h2>
      </div>

      <div className="stats-grid">
        <div className="stat-card">
          <h3>{stats.total}</h3>
          <p>Total Complaints</p>
        </div>
        <div className="stat-card">
          <h3>{stats.pending}</h3>
          <p>Pending</p>
        </div>
        <div className="stat-card">
          <h3>{stats.inProgress}</h3>
          <p>In Progress</p>
        </div>
        <div className="stat-card">
          <h3>{stats.resolved}</h3>
          <p>Resolved</p>
        </div>
      </div>

      {loading && <p>Loading complaints...</p>}

      <div className="complaints-list">
        {complaints.map((complaint) => (
          <div
            key={complaint.id}
            className={`complaint-item status-${complaint.status}`}
            onClick={() => setSelectedComplaint(complaint)}
          >
            <div className="complaint-header">
              <h3>Complaint #{complaint.id}</h3>
              <span className={`status-badge ${complaint.status}`}>
                {complaint.status.replace('_', ' ').toUpperCase()}
              </span>
            </div>
            <p><strong>Type:</strong> {complaint.type}</p>
            <p><strong>Village:</strong> {complaint.village}</p>
            <p><strong>Filed:</strong> {new Date(complaint.createdAt).toLocaleDateString()}</p>
          </div>
        ))}
      </div>

      {selectedComplaint && (
        <div className="modal-overlay" onClick={() => setSelectedComplaint(null)}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()}>
            <span className="close-btn" onClick={() => setSelectedComplaint(null)}>&times;</span>
            <h2>Complaint Details</h2>
            <div className="complaint-details">
              <p><strong>ID:</strong> {selectedComplaint.id}</p>
              <p><strong>Type:</strong> {selectedComplaint.type}</p>
              <p><strong>Village:</strong> {selectedComplaint.village}</p>
              <p><strong>Description:</strong> {selectedComplaint.description}</p>
              <p><strong>Status:</strong> {selectedComplaint.status}</p>
              <p><strong>Filed:</strong> {new Date(selectedComplaint.createdAt).toLocaleString()}</p>
            </div>
            <div className="action-buttons">
              <button onClick={() => handleStatusUpdate(selectedComplaint.id, 'pending')} className="action-btn">
                Mark as Pending
              </button>
              <button onClick={() => handleStatusUpdate(selectedComplaint.id, 'in_progress')} className="action-btn in-progress">
                Mark as In Progress
              </button>
              <button onClick={() => handleStatusUpdate(selectedComplaint.id, 'resolved')} className="action-btn resolved">
                Mark as Resolved
              </button>
            </div>
          </div>
        </div>
      )}

      {complaints.length === 0 && !loading && (
        <p className="no-data">No complaints filed yet.</p>
      )}
    </div>
  );
};

export default ComplaintAnalysis;
